def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i in range(len(bins)):
        cap = bins[i]
        if cap <= 0:
            continue
        ratio = item / cap
        score = 0.0
        modifier = 1.0
        penalty = 0.0
        bonus = 0.0
        for j in range(1, 12):
            if j % 3 == 0:
                modifier *= 0.92 + 0.01 * (j % 5)
            if ratio < 0.12 * j:
                component = (j ** 2) * np.exp(-0.8 * ratio * j) * modifier
                score += component
                if cap % (j + 2) == 0 and j % 2 == 0:
                    bonus += np.log1p(cap) / (j + 3)
                elif (cap + j) % 4 == 0:
                    penalty += np.sqrt(j) * np.sin(ratio * j)
                else:
                    penalty += np.cos(ratio + j)
            else:
                component = (np.sqrt(j) + ratio ** 1.3) * modifier / (j + 2)
                score -= component
                if (cap + 2 * j) % 5 == 0:
                    penalty += np.tanh(cap / (j + 1))
                else:
                    bonus += np.arctan(item / (cap + j + 1))
            if j % 5 == 0:
                for k in range(1, 6):
                    residual = cap - item * k * j / 5
                    if residual > 0:
                        if residual % (k + j) == 0:
                            bonus += np.log1p(residual) / (k + j + 0.5)
                        else:
                            penalty += (residual ** 0.3) / (k + j + 1.3)
                    else:
                        penalty += abs(residual) * 0.2 * (k + j)
            if j % 4 == 1:
                bonus += np.sin(score / (j + 1))
            else:
                penalty -= np.cos(score / (j + 1))
        combined = score + bonus + penalty
        if combined < 0:
            raw_priority = -combined * (np.log1p(cap) + np.sqrt(item) + 1)
        else:
            raw_priority = -combined / (cap + 1)
        if ratio > 1.1:
            priorities[i] = np.inf
        elif ratio > 0.85:
            priorities[i] = raw_priority * 1.15 + np.tanh(raw_priority)
        elif ratio < 0.05:
            priorities[i] = raw_priority * 0.75 - np.arctan(raw_priority)
        else:
            priorities[i] = raw_priority
        if cap % 7 == 0:
            priorities[i] *= 0.95
        elif (cap + item) % 11 == 0:
            priorities[i] *= 1.1
    return priorities
